```typescript
import { Effect, Data } from "effect";

class ErrA extends Data.TaggedError("ErrA")<{ readonly a: number }> {}
class ErrB extends Data.TaggedError("ErrB")<{ readonly b: string }> {}

declare const risky: Effect.Effect<number, ErrA | ErrB>;

// catchAll erases the whole error channel in one shot.
export const safe: Effect.Effect<number, never> = risky.pipe(
  Effect.catchAll((_e) => Effect.succeed(0)),
);
```

`Effect.catchAll` takes every error on the channel and hands you a single handler — the residual error type becomes `never` (unless the handler itself fails). `Effect.catchTag` is narrow: it matches exactly one `_tag` and leaves the rest. `Effect.catchTags` is the bulk form — an object keyed by `_tag`, handy when you want to recover from several specific tags but keep others on the channel.

```typescript
import { Effect, Data } from "effect";

class NetErr extends Data.TaggedError("NetErr")<{ readonly url: string }> {}
class AuthErr extends Data.TaggedError("AuthErr")<{ readonly user: string }> {}
class BugErr extends Data.TaggedError("BugErr")<{ readonly msg: string }> {}

declare const run: Effect.Effect<number, NetErr | AuthErr | BugErr>;

export const demo: Effect.Effect<number, never> = run.pipe(
  // Narrow: handle one tag only.
  Effect.catchTag("NetErr", (_e) => Effect.succeed(-1)),
  // Bulk: handle several remaining tags at once.
  Effect.catchTags({
    AuthErr: (_e) => Effect.succeed(-2),
  }),
  // Sweep: everything left falls through here.
  Effect.catchAll((_e) => Effect.succeed(-999)),
);
```

