import { Effect, Either, Data } from "effect";

export class NaNErr extends Data.TaggedError("NaNErr")<{ readonly raw: string }> {}
export class NotPositive extends Data.TaggedError("NotPositive")<{
  readonly value: number;
}> {}

const toInt = (raw: string): Either.Either<number, NaNErr> => {
  const n = Number(raw);
  return Number.isInteger(n) ? Either.right(n) : Either.left(new NaNErr({ raw }));
};

const requirePositive = (n: number): Either.Either<number, NotPositive> =>
  n > 0 ? Either.right(n) : Either.left(new NotPositive({ value: n }));

export const parsePositive = (
  raw: string,
): Effect.Effect<number, NaNErr | NotPositive> =>
  Effect.fromEither(toInt(raw)).pipe(
    Effect.flatMap((n) => Effect.fromEither(requirePositive(n))),
  );
```

Use `Effect.fromEither` when the upstream already returned a typed `Either` — the left becomes the effect's error channel with no extra mapping. Use `Effect.fromNullable` when you're importing a JS API that returns `T | null | undefined` — the library wraps missing values in a built-in error you can `mapError` to your own tag. Match on `Option` explicitly when you want to choose between `Effect.succeed` and `Effect.fail` with different tags (or with context) and don't want the library's default error.

```typescript
import { Effect, Either, Option, Data } from "effect";

export class Missing extends Data.TaggedError("Missing")<{ readonly key: string }> {}
export class Invalid extends Data.TaggedError("Invalid")<{ readonly raw: string }> {}

declare const raw: Either.Either<number, Invalid>;
declare const maybe: string | undefined;
declare const opt: Option.Option<boolean>;

export const prog: Effect.Effect<number, Invalid | Missing> = Effect.gen(function* () {
  const n = yield* Effect.fromEither(raw);
  const s = yield* Effect.fromNullable(maybe).pipe(
    Effect.mapError(() => new Missing({ key: "maybe" })),
  );
  const b = yield* Option.match(opt, {
    onNone: () => Effect.fail(new Missing({ key: "opt" })),
    onSome: (x) => Effect.succeed(x),
  });
  return n + s.length + (b ? 1 : 0);
});
```

