class AuthErr extends Data.TaggedError("AuthErr")<{ readonly user: string }> {}

declare const call: Effect.Effect<string, NetErr | AuthErr>;

const policy = Schedule.exponential(Duration.millis(50)).pipe(
  Schedule.intersect(Schedule.recurs(5)),
  Schedule.whileInput((e: NetErr | AuthErr) => e._tag === "NetErr"),
);

export const robust = Effect.retry(call, policy);
