import { Effect, Data } from "effect";

class TagA extends Data.TaggedError("TagA")<{ readonly a: string }> {}
class TagB extends Data.TaggedError("TagB")<{ readonly b: number }> {}
class TagC extends Data.TaggedError("TagC")<{ readonly c: boolean }> {}

type Err = TagA | TagB | TagC;

const describe = (e: Err): string => {
  switch (e._tag) {
    case "TagA":
      return `a=${e.a}`;
    case "TagB":
      return `b=${e.b}`;
    case "TagC":
      return `c=${e.c}`;
    default: {
      // Adding a fourth tag without extending this switch is a type error.
      const _exhaustive: never = e;
      return _exhaustive;
    }
  }
};

declare const work: Effect.Effect<number, Err>;

export const program: Effect.Effect<string, never> = work.pipe(
  Effect.match({
    onFailure: describe,
    onSuccess: (n) => `ok:${n}`,
  }),
);
