import { Effect, Data } from "effect";

class E1 extends Data.TaggedError("E1")<{ readonly x: number }> {}
class E2 extends Data.TaggedError("E2")<{ readonly y: string }> {}

type Err = E1 | E2;

export const toMessage = (e: Err): string => {
  switch (e._tag) {
    case "E1":
      return `e1:${e.x}`;
    case "E2":
      return `e2:${e.y}`;
    default: {
      // Adding E3 to `Err` without a case here triggers a TS error.
      const _never: never = e;
      return _never;
    }
  }
};

declare const risky: Effect.Effect<number, Err>;

// catchAll + exhaustive switch = total recovery.
export const safe: Effect.Effect<string, never> = risky.pipe(
  Effect.catchAll((e) => Effect.succeed(toMessage(e))),
  Effect.map((s) => s.toUpperCase()),
);
