import { Effect, Data } from "effect";

export class E1 extends Data.TaggedError("E1")<{ readonly x: number }> {}
export class E2 extends Data.TaggedError("E2")<{ readonly y: string }> {}

type Err = E1 | E2;

// Switch with a `never` fallthrough so adding E3 is a compile error —
// the ternary in the original snippet silently returned "b" for any new tag.
export const f = (e: Err): string => {
  switch (e._tag) {
    case "E1":
      return `x=${e.x}`;
    case "E2":
      return `y=${e.y}`;
    default: {
      const _exhaustive: never = e;
      return _exhaustive;
    }
  }
};

// Example use with Effect.catchAll so callers get a typed recovery pipeline.
declare const job: Effect.Effect<number, Err>;
export const run: Effect.Effect<string, never> = job.pipe(
  Effect.catchAll((e) => Effect.succeed(f(e))),
);
