import { Effect, Data } from "effect";

class TimeoutErr extends Data.TaggedError("TimeoutErr")<{ readonly ms: number }> {}
class NetErr extends Data.TaggedError("NetErr")<{ readonly url: string }> {}
class AuthErr extends Data.TaggedError("AuthErr")<{ readonly user: string }> {}
class ParseErr extends Data.TaggedError("ParseErr")<{ readonly raw: string }> {}

type Err = TimeoutErr | NetErr | AuthErr | ParseErr;

const describe = (e: Err): string => {
  switch (e._tag) {
    case "TimeoutErr":
      return `timeout:${e.ms}ms`;
    case "NetErr":
      return `net:${e.url}`;
    case "AuthErr":
      return `auth:${e.user}`;
    case "ParseErr":
      return `parse:${e.raw}`;
    default: {
      const _exhaustive: never = e;
      return _exhaustive;
    }
  }
};

declare const run: Effect.Effect<number, Err>;

export const program: Effect.Effect<string, never> = run.pipe(
  Effect.match({
    onFailure: describe,
    onSuccess: (n) => `ok:${n}`,
  }),
);
